package adt;import java.util.Iterator;/** * An interface for the ADT sorted list. Entries in the list have positions that begin with 1. * @author Frank M. Carrano * @version 2.0 */// bitch        public interface SortedListInterface<T extends Comparable<T>> {    /**     * Description : Adds newEntry to the sorted list such that the list remains sorted.     * Post-condition : newEntry has been added to the sorted list in a position which ensures that the list remains sorted.     * Returns : true if anEntry was added, else false.     */    public boolean add(T newEntry);            /**     * Description : Removes the first or only occurrence of anEntry from the sorted list.     * Post-condition : anEntry has been removed from the list. If anEntry was not located in the list, the list remains unchanged.     * Returns : true if anEntry was located and removed, else false.     */    public boolean remove(T anEntry);        /**     * Description : Removes all entries from the list.     * Post-condition : The list is now empty.     */    public void clear();        /**     * Description : Determines whether the list contains anEntry.     * Post-condition : The list remains unchanged.      * Returns : true if anEntry is in the list, or false if not.     */    public boolean contains(T anEntry);        /**     * Description : Gets the number of entries currently in the list.     * Post-condition : The list remains unchanged.      * Returns : The number of entries currently in the list.     */    public int getNumberOfEntries();        /**     * Description : Determines whether the list is empty.     * Post-condition : The list remains unchanged.     * Returns : true if the list is empty, or false if not.      */    public boolean isEmpty();        public Iterator<T> getIterator();}